int main() {
	using namespace std::chrono_literals;

	auto start = std::chrono::high_resolution_clock::now();
	int numLines = 1000000;

	std::ofstream out("data.txt");
	for (int i = 1; i < (numLines+1); i++)
		out << i << std::endl;
	out.close();

